def assess(record: dict) -> str:
    required = {"case_id", 'use', 'queue_rank', 'out_of_scope', 'fraud_label', 'contestability'}
    missing = sorted(required - record.keys())
    if missing:
        return "MISSING:" + ",".join(missing)
    return "PASS" if not (record["use"] == "fraud_label") else "REJECT_SCOPE_BREACH"

valid = {"case_id": "CASO-LIM-035-4A", **{'use': 'queue_rank', 'out_of_scope': ['fraud_label'], 'contestability': True}}
invalid = {"case_id": "CASO-LIM-035-4A", **{'use': 'queue_rank', 'out_of_scope': ['fraud_label'], 'contestability': True}}
# adversarial: flip domain flag from packet rule
if "catalog_ok" in invalid:
    invalid = {**invalid, "catalog_ok": False}
elif "means_fraud" in invalid:
    invalid = {**invalid, "means_fraud": True}
elif "causal" in invalid:
    invalid = {**invalid, "causal": True}
elif "use" in invalid:
    invalid = {**invalid, "use": "fraud_label"}
incomplete = {**valid}
incomplete.pop("out_of_scope", None)
results = (assess(valid), assess(invalid), assess(incomplete))
print(*results)

def decide(record: dict) -> str:
    required = {"case_id", 'use', 'queue_rank', 'out_of_scope', 'fraud_label', 'contestability'}
    missing = sorted(required - record.keys())
    if missing:
        return "REQUEST_CARD_KEYS"
    return "CONTINUE" if not (record["use"] == "fraud_label") else "REJECT_SCOPE_BREACH"

valid = {"case_id": "CASO-LIM-035-4A", **{'use': 'queue_rank', 'out_of_scope': ['fraud_label'], 'contestability': True}}
invalid = dict(valid)
if "catalog_ok" in invalid:
    invalid["catalog_ok"] = False
elif "means_fraud" in invalid:
    invalid["means_fraud"] = True
elif "causal" in invalid:
    invalid["causal"] = True
elif "use" in invalid:
    invalid["use"] = "fraud_label"
elif "depth_unlimited" in invalid:
    invalid["depth_unlimited"] = True
uncertain = {**valid}
uncertain.pop("out_of_scope", None)
results = [decide(item) for item in (valid, invalid, uncertain)]
print(*results)

